{
  "type": "object",
  "properties": {
    "job_plan_filename": {
      "type": "string",
      "description": "Calculated filename. Strip 'SOP/sop', keep the leading number, append 'Job Plan' right after the number (e.g., '41. Job Plan Sprinklers...')."
    },
    "job_plan_id_name": {
      "type": "string",
      "description": "The combined Activity and Site Location for the main header (e.g., 'Sprinklers - 250 East Carol Way Well')."
    },
    "purpose_scope": {
      "type": "string",
      "description": "Relevant job information and purpose statement extracted from the SOP."
    },
    "approved_by": {
      "type": "string",
      "description": "The name next to 'Approved By:' in the SOP. Null if blank or missing."
    },
    "preparation_work": {
      "type": "string",
      "description": "Any pre-work, isolation, or setup text required before tasks begin. Null if none."
    },
    "safety_requirements": {
      "type": "string",
      "description": "PPE, hazards, or safety warnings mentioned in the SOP. Null if none."
    },
    "maintenance_tasks": {
      "type": "array",
      "description": "Chronological procedure steps and section headers for the main table.",
      "items": {
        "type": "object",
        "properties": {
          "is_section_header": {
            "type": "boolean",
            "description": "True if this row is a merged header naming a phase (e.g., 'ON PROCEDURES'). False for standard steps."
          },
          "section_name": {
            "type": "string",
            "description": "The name of the phase/procedure in ALL CAPS if is_section_header is true. Otherwise null."
          },
          "order": {
            "type": "integer",
            "description": "Sequential step number starting from 1 for each phase. Null if is_section_header is true."
          },
          "task": {
            "type": "string",
            "description": "A brief, punchy action phrase consisting of exactly 2 to 4 words. Null if is_section_header is true."
          },
          "description": {
            "type": "string",
            "description": "The rewritten, crystal-clear, direct step instructions. Preserves asset names and image filenames verbatim."
          }
        },
        "required": ["is_section_header", "section_name", "order", "task", "description"]
      }
    },
    "labor_information": {
      "type": "array",
      "description": "Extracted labor, trades, or contractor requirements.",
      "items": {
        "type": "object",
        "properties": {
          "trade_craft": { "type": "string" },
          "skill_level": { "type": "string" },
          "number_needed": { "type": "integer" },
          "estimated_hours": { "type": "number" }
        }
      }
    },
    "training_requirements": {
      "type": "array",
      "description": "Specialized training required (safety, technical, etc.).",
      "items": {
        "type": "object",
        "properties": {
          "training_name": { "type": "string" },
          "level": { "type": "string" },
          "certified": { "type": "string" },
          "frequency": { "type": "string" }
        }
      }
    },
    "materials": {
      "type": "array",
      "description": "Parts, materials, or consumables needed.",
      "items": {
        "type": "object",
        "properties": {
          "item_number": { "type": "string" },
          "quantity": { "type": "integer" },
          "stock_status": { "type": "string", "description": "Stock or Non-Stock" }
        }
      }
    },
    "tools": {
      "type": "array",
      "description": "Specialized tools and equipment required to perform the task.",
      "items": {
        "type": "object",
        "properties": {
          "tool_name": { "type": "string", "description": "e.g., fork key, compressor adapter" },
          "associated_task_id": { "type": "string" },
          "quantity": { "type": "integer" },
          "service_type": { "type": "string", "description": "Inside or Outside" },
          "specific_equipment": { "type": "string" },
          "operator_hours": { "type": "number" }
        }
      }
    },
    "references": {
      "type": "string",
      "description": "Any manuals, drawings, or documents referenced by the SOP. Null if none."
    }
  },
  "required": [
    "job_plan_filename",
    "job_plan_id_name",
    "purpose_scope",
    "approved_by",
    "preparation_work",
    "safety_requirements",
    "maintenance_tasks",
    "labor_information",
    "training_requirements",
    "materials",
    "tools",
    "references"
  ]
}

