// Import n8n's native mammoth library to parse docx files
const mammoth = require('mammoth');

const items = this.getInputData();
const returnData = [];

for (let item of items) {
  // 1. Look for the binary file 'data' coming from Google Cloud Storage
  const binaryData = item.binary?.data;

  if (!binaryData) {
    throw new Error("No binary data found under the property 'data'. Check your storage node output.");
  }

  // 2. Convert the base64 binary string into a buffer mammoth can read
  const fileBuffer = Buffer.from(binaryData.data, 'base64');

  // 3. Extract the plain text from the raw Word document structure
  const result = await mammoth.extractRawText({ buffer: fileBuffer });
  const textContent = result.value;

  // 4. Push the clean text and file metadata forward to the AI Chain
  returnData.push({
    json: {
      text: textContent,
      name: binaryData.fileName || "unknown_sop.docx"
    }
  });
}

return returnData;
